#include <algorithm>
#include <vector>
#include <cstdint>

using Int64 = int64_t;

Int64 solve(std::vector<Int64> piles) {
    int n = piles.size();
    int groups = n / 3;
    std::vector<Int64> sorted_piles = piles;
    std::sort(sorted_piles.begin(), sorted_piles.end());
    Int64 total = 0;
    for (int i = 1; i <= groups; i++) {
        int index = n - 2 * i;
        total += sorted_piles[index];
    }
    return total;
}
```

